const resolvers = {
  Query: {
    order: async (_parent, { id }, ctx) => {
      if (!ctx.user) throw new Error('Unauthorized'); // sadece login!
      // id=124 dersem komşunun siparişini okurum
      return db.order.findById(id);
    },
  },
};

const resolvers = {
  Query: {
    order: async (_parent, { id }, ctx) => {
      // 1) Kimlik
      requireAuth(ctx);
      // 2) İzin (RBAC/ABAC) — {{ref:k-authz}}
      requirePermission(ctx, 'order:read');
      // 3) Tenant scope — {{ref:k-tenancy}} (RLS de aynı şeyi DB'de zorlar)
      const order = await db.order.findOne({
        id,
        tenantId: ctx.tenantId, // client'tan DEĞİL, ctx'ten
      });
      if (!order) throw new NotFoundError('order'); // 404, 403 değil (varlık sızdırma)
      // 4) Object ownership — kayıt bu kullanıcıya mı bağlı?
      assertOwnership(ctx, order); // ör. order.customerId === ctx.user.id
      return order;
    },
  },
};

const User = {
  // name: parent.name  -> serbest
  salary: (parent, _args, ctx) => {
    if (!hasPermission(ctx, 'hr:salary:read')) return null; // sızdırma yok
    return parent.salary; // Decimal
  },
  identityNumber: (parent, _args, ctx) => {
    if (!hasPermission(ctx, 'pii:identity:read')) return null;
    auditPiiAccess(ctx, parent.id, 'identityNumber'); // PII erişimi loglanır
    return parent.identityNumber;
  },
};

