  Query: {
    orders: async (_p, { first, after }, ctx) => {
      requireAuth(ctx);
      requirePermission(ctx, 'order:list');
      return db.order.paginate({
        where: { tenantId: ctx.tenantId }, // JWT/session'dan, client'tan DEĞİL
