// ctx kurulumu (her istek): tenantId yalnız doğrulanmış token'dan
function buildContext(req) {
  const claims = verifyJwt(req.headers.authorization);
  return { user: claims.sub, tenantId: claims.tenant_id, roles: claims.roles };
}

