// Build çıktısı: { "a1b2c3...": "query Orders($f:Int!){ orders(first:$f){...} }", ... }
import allowlist from './persisted-operations.json';

const server = new ApolloServer({
  schema,
  persistedQueries: { cache: redisCache },
  extensions: [{
    async requestDidStart() {
      return {
        async didResolveOperation(rc) {
          const hash = rc.request.extensions?.persistedQuery?.sha256Hash;
          if (!hash || !allowlist[hash]) {
            throw new ForbiddenError('Operation not allowed'); // keyfi sorgu RED
          }
        },
      };
    },
  }],
});

