function clampFirst(first?: number): number {
  const DEFAULT = 20, MAX = 100;
  if (first == null) return DEFAULT;
  if (first < 1) throw new UserInputError('first must be >= 1');
  return Math.min(first, MAX); // 10_000 istense bile 100
}

