  c: login(email:"v@x.com", password:"1236")
  # ... tek istekte 500 deneme — naif rate-limit 'tek istek' sayar
}

const SENSITIVE = new Set(['login', 'requestOtp', 'passwordReset', 'invite']);

const guardExtension = {
  async requestDidStart() {
    return {
      async didResolveOperation(rc) {
        const ops = collectRootFields(rc.document); // alias'lar dahil
        const sensitive = ops.filter(o => SENSITIVE.has(o.fieldName));
        // hassas mutation tek istekte 1'den fazla / alias'lı ise RED
        if (sensitive.length > 1) throw new ForbiddenError('Batching not allowed for sensitive ops');
        for (const op of sensitive) {
          await rateLimit({ key: rc.context.ip, op: op.fieldName, max: 5, windowSec: 60 });
          await rateLimit({ key: rc.context.user ?? rc.context.email, op: op.fieldName, max: 5, windowSec: 300 });
          await rateLimit({ key: rc.context.tenantId, op: op.fieldName, max: 50, windowSec: 60 });
        }
      },
    };
  },
};

