// Resolver dış URL çağrısı (ör. webhook test, avatar fetch): SSRF kısıtı
function assertSafeUrl(u: URL) {
  if (!['https:'].includes(u.protocol)) throw new UserInputError('only https');
  if (isPrivateIp(u.hostname) || u.hostname === 'localhost') throw new ForbiddenError('SSRF blocked');
  if (!HOST_ALLOWLIST.has(u.hostname)) throw new ForbiddenError('host not allowed');
}
